37: 
38:   /**
39:    * The Black (lognormal) model.
40:    * This uses Black volatilities - {@link BlackFxOptionVolatilities}.
41:    */
42:   BLACK,
43:   /**
44:    * The Vanna-Volga model.
45:    * This uses Black volatilities based on a smile - {@link BlackFxOptionSmileVolatilities}.
46:    */
47:   VANNA_VOLGA;
